// Get the call-off worker's employee record
const employeeRecord = $('Search Records of Call Off Worker').first();
if (!employeeRecord) return [{ json: { id: null, noShiftFound: true } }];

// The Airtable Employees record ID (e.g. "recobw7UdAyGy6zWV")
const employeeId = employeeRecord.json.id;

// Define today in America/Los_Angeles timezone
const formatter = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'America/Los_Angeles',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
});
const todayStr = formatter.format(new Date());

const allShifts = $input.all();

const todaysShifts = allShifts.filter(item => {
  // WorkFlow2-1: Airtable returns flat json (no .fields wrapper)
  // But safely support both formats just in case
  const shift = item.json.fields ?? item.json;

  // "Employee ID" is a linked record array like ["recobw7UdAyGy6zWV"]
  const empField = shift['Employee ID'] ?? shift['Employee'] ?? [];
  const employeeMatch = Array.isArray(empField)
    ? empField.includes(employeeId)
    : empField === employeeId;

  if (!employeeMatch) return false;

  // "Shift Date/Time" is the date field in Call-Off History
  // "Start" is used in Employee Shift table — check both
  const startVal = shift['Shift Date/Time'] ?? shift['Start'] ?? shift['Shift DateTime'];
  if (!startVal) return false;

  const shiftDateStr = formatter.format(new Date(startVal));
  return shiftDateStr === todayStr;
});

if (todaysShifts.length === 0) {
  return [{ json: { id: null, noShiftFound: true } }];
}

// Flatten output: merge record id + fields into one clean object
return todaysShifts.map(item => {
  const raw = item.json;
  const fields = raw.fields ?? raw;
  return {
    json: {
      id: raw.id ?? null,
      ...fields
    },
    pairedItem: item.pairedItem
  };
});
